const r = $input.first().json.report || {};
const issues = Object.entries(r).filter(([k,v]) => Number(v) > 0);
const totalIssues = issues.reduce((s, [k,v]) => s + Number(v), 0);
return [{ json: { total_issues: totalIssues, issues_breakdown: Object.fromEntries(issues), report: r, has_issues: totalIssues > 0 } }];
